(() => { 
                const root = {{DOM_CONTEXT}}; 
                if (!root) return;
                const wrap = root.querySelector('#tag-spec-wrap'); 
                if (!wrap) return;
                const container = root.parentElement || document.body;

                setInterval(() => {
                    let lifted = false;
                    if (container.querySelector('.lt-container')) {
                        lifted = true;
                    }
                    wrap.style.bottom = lifted ? '285px' : '115px'; 
                }, 100);
            })();
